 const slots = {};

for (const item of items) {

  const start = item.json.start?.dateTime;

  if (!start) continue;

  const date = new Date(start);

  const hour = date.toLocaleString("es-ES", {
    timeZone: "Europe/Madrid",
    hour: "2-digit",
    hour12: false
  }) + ":00";

  if (!slots[hour]) {
    slots[hour] = 0;
  }

  slots[hour]++;
}

const horasDelDia = [
  "09:00","10:00","11:00","12:00",
  "13:00","14:00","15:00","16:00"
];

const disponibilidad = [];

for (const hora of horasDelDia) {

  const citas = slots[hora] || 0;

  if (citas < 2) {
    disponibilidad.push({
      hora,
      citas
    });
  }
}

return disponibilidad.map(h => ({ json: h }));

